import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { loginUser } from '../utils/api';

function Login({ onLogin }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false); // FIX: Guard state flag
  const navigate = useNavigate();

  function handleSubmit(e) {
    e.preventDefault();
    if (username === "" || password === "") {
      alert("Fields must not be empty!");
      return;
    }

    setLoading(true); // LOCK button to prevent multi-submit bugs

    loginUser(username.trim().normalize("NFC"), password)
      .then(response => {
        if (response.token) {
          onLogin({
            username: username,
            token: response.token,
            role: response.role || "user"
          });
          navigate("/dashboard");
        } else {
          alert("Authentication credentials failure update!");
        }
      })
      .catch(err => console.error(err))
      .finally(() => setLoading(false)); // UNLOCK button
  }

  return (
    <div className="login-form">
      <h2>Secure Portal Connection Setup</h2>
      <form onSubmit={handleSubmit}>
        <input type="text" value={username} onChange={e => setUsername(e.target.value)} placeholder="Username" />
        <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" />
        <button type="submit" disabled={loading}>
          {loading ? "Processing..." : "Login"}
        </button>
      </form>
    </div>
  );
}

export default Login;
